commands.command:
Text {
    text: "Hello, World!"
    font.pointSize: 20
    anchors.centerIn: parent
}

Rectangle {
    width: 200
    height: 200
    color: "blue"
    Rectangle {
        width: 100
        height: 100
        color: "green"
        anchors.centerIn: parent
    }
}

Button {
    text: "Click me"
    onClicked: console.log("Button clicked!")
}

Item {
    signal mySignal(string message)
    Component.onCompleted: mySignal("Hello")
}

Rectangle {
    width: 100
    height: 100
    signal clicked()
    MouseArea {
        anchors.fill: parent
        onClicked: parent.clicked()
    }
    onClicked: console.log("Rectangle clicked")
}

Rectangle {
    width: 100
    height: 100
    color: "red"
    Rectangle {
        width: parent.width / 2
        height: parent.height / 2
        color: "green"
    }
}

Rectangle {
    width: 100
    height: 100
    property int counter: 0
    Text {
        text: "Counter: " + parent.counter
    }
}

Rectangle {
    width: 100
    height: 100
    color: "red"
    SequentialAnimation {
        NumberAnimation { target: parent; property: "width"; to: 200; duration: 1000 }
        NumberAnimation { target: parent; property: "width"; to: 100; duration: 1000 }
    }
}

Row {
    spacing: 10
    Rectangle { width: 50; height: 50; color: "red" }
    Rectangle { width: 50; height: 50; color: "green" }
}

Column {
    spacing: 10
    Rectangle { width: 50; height: 50; color: "blue" }
    Rectangle { width: 50; height: 50; color: "yellow" }
}

Rectangle {
    width: 200
    height: 200
    color: "lightgray"
    Rectangle {
        width: 100
        height: 100
        color: "purple"
        anchors.centerIn: parent
    }
}

Rectangle {
    width: 100
    height: 100
    color: "red"
    states: [
        State {
            name: "greenState"
            PropertyChanges { target: rectangle; color: "green" }
        }
    ]
    MouseArea {
        anchors.fill: parent
        onClicked: rectangle.state = "greenState"
    }
}

Rectangle {
    width: 100
    height: 100
    color: "red"
    states: State {
        name: "expanded"
        PropertyChanges { target: rectangle; width: 200 }
    }
    transitions: Transition {
        NumberAnimation { properties: "width"; duration: 500 }
    }
}

Rectangle {
    width: 100
    height: 100
    color: "red"
    MouseArea {
        anchors.fill: parent
        onClicked: {
            rectangle.state = (rectangle.state === "") ? "expanded" : ""
        }
    }
}
